# conftest.py — set Allure metadata from BDD tags
import allure
import pytest

def pytest_bdd_before_scenario(request, feature, scenario):
    """Set Allure metadata based on BDD tags before each scenario runs."""
    tags = {tag.name for tag in scenario.tags}

    # Map @area:X tag to Allure epic
    for tag in tags:
        if tag.startswith("area:"):
            allure.dynamic.epic(tag.split(":", 1)[1].replace("-", " ").title())
        elif tag.startswith("capability:"):
            allure.dynamic.feature(tag.split(":", 1)[1].replace("-", " ").title())

    # Set story to the scenario name
    allure.dynamic.story(scenario.name)

    # Severity mapping
    if "smoke" in tags:
        allure.dynamic.severity(allure.severity_level.CRITICAL)
    elif "boundary" in tags:
        allure.dynamic.severity(allure.severity_level.NORMAL)

# scripts/check_doc_rot.py — detect signs of documentation rot in feature files
import re
from pathlib import Path

def check_rot(feature_dir: str) -> list[dict]:
    issues = []
    for path in Path(feature_dir).rglob("*.feature"):
        content = path.read_text()
        lines = content.splitlines()

        # Count skipped scenarios
        skip_count = sum(1 for line in lines if "@skip" in line.lower() or "@xfail" in line.lower())
        scenario_count = sum(1 for line in lines if line.strip().startswith("Scenario"))

        if skip_count > 0:
            issues.append({
                "file": str(path),
                "issue": "skipped_scenarios",
                "detail": f"{skip_count}/{scenario_count} scenarios are skipped",
                "severity": "high" if skip_count / max(scenario_count, 1) > 0.2 else "medium",
            })

        # Check for TODO comments (spec not yet implemented)
        todo_count = sum(1 for line in lines if "TODO" in line or "FIXME" in line or "PENDING" in line)
        if todo_count > 0:
            issues.append({
                "file": str(path),
                "issue": "pending_spec",
                "detail": f"{todo_count} TODO/PENDING comments found",
                "severity": "medium",
            })

        # Check for very old scenarios (no step definitions would cause import errors,
        # but we can check for scenarios with no @eval: tags — missing coverage link)
        no_eval_scenarios = [
            m.group(1) for m in re.finditer(r"Scenario:\s+(.+)", content)
            if not re.search(r"@eval:", content[:content.find(m.group(0))])
        ]
        if no_eval_scenarios:
            issues.append({
                "file": str(path),
                "issue": "no_eval_link",
                "detail": f"{len(no_eval_scenarios)} scenarios have no @eval: tag",
                "severity": "low",
            })

    return issues

if __name__ == "__main__":
    issues = check_rot("features/")
    if issues:
        print(f"Found {len(issues)} documentation rot issues:")
        for issue in issues:
            print(f"  [{issue['severity'].upper()}] {issue['file']}: {issue['detail']}")
    else:
        print("No documentation rot detected.")
